def latest_time(s: str) -> str:
    s = list(s)

    # Handle hour tens digit
    if s[0] == '?':
        if s[1] == '?' or int(s[1]) <= 1:
            s[0] = '1'
        else:
            s[0] = '0'

    # Handle hour units digit
    if s[1] == '?':
        if s[0] == '1':
            s[1] = '1'
        else:
            s[1] = '9'

    # Handle minute tens digit
    if s[3] == '?':
        s[3] = '5'

    # Handle minute units digit
    if s[4] == '?':
        s[4] = '9'

    return ''.join(s)
